import { createContext, useContext, useEffect, useMemo, useRef, useState } from "react";
import { Link, NavLink, Navigate, Route, Routes, useLocation, useNavigate, useParams } from "react-router-dom";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import {
  Archive, ArrowLeft, ArrowRight, BarChart3, Bell, CalendarDays, Check, CheckCircle2, ChevronDown,
  ChevronRight, CircleHelp, CloudUpload, Command, CreditCard, ExternalLink, Eye, Facebook, FileImage,
  Gauge, Image, Layers3, LayoutDashboard, Link2, LogOut, Menu, Pause, Pencil, Play, Plus, RefreshCw,
  Search, Settings, ShieldCheck, Sparkles, Target, Trash2, UploadCloud, Users, Video, X, Zap
} from "lucide-react";
